#include <stdio.h>
#include <stdbool.h>

bool isPalindrome(int x) {
    int orig = x, rev = 0;
    while (x > 0) {
        rev = rev * 10 + x % 10;
        x /= 10;
    }
    return rev == orig;
}

int main() {
    const int MAX = 100000;
    static long long pref[MAX + 1];
    pref[0] = 0;
    for (int i = 1; i <= MAX; ++i) {
        pref[i] = pref[i - 1] + (isPalindrome(i) ? i : 0);
    }
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        long long ans = pref[R] - (L > 0 ? pref[L - 1] : 0);
        printf("%lld\n", ans);
    }
    return 0;
}

